def comb_sort(arr):
  n = len(arr)
  gap = n 
  while gap > 0:
    for i in range(n - gap):
      if arr[i] > arr[i + gap]:
        arr[i], arr[i + gap] = arr[i + gap], arr[i]
    gap //= 2
  return arr
```

