def get_gcd(arr):
  """Finds the greatest common divisor (GCD) of an array of integers.

  Args:
    arr: A list of integers.

  Returns:
    The GCD of all elements in the array.
  """
  if len(arr) == 0:
    return 0
  else:
    return _gcd(arr[0], arr[1])

def _gcd(a, b):
  while b:
    a, b = b, a % b
  return a
```

