def rearrange_string(s):
  """
  Checks if the letters of a given string can be rearranged so that two characters that are adjacent to each other are different.

  Args:
    s: The input string.

  Returns:
    True if the letters can be rearranged, False otherwise.
  """
  char_counts = {}
  for char in s:
    if char in char_counts:
      char_counts[char] += 1
    else:
      char_counts[char] = 1

  # Check if there are at least two characters with a count of 2 or more.
  for count in char_counts.values():
    if count >= 2:
      return False

  return True
```

